  ('elementary-64311456-moex-00714', 'elementary-64311456', 'elementary-64311456-moex-111-1f300fa3', 'sub-elementary-64311456-03', NULL, 'single_choice', '中高齡者及高齡者就業促進法對求職或受僱之中高齡者及高齡者，不得以年齡為由予以差別待遇。因此 在第14條明定，求職或受僱之中高齡者及高齡者於釋明差別待遇之事實後，應由誰就差別待遇之非年齡 因素，或其符合前條所定之差別待遇因素，負舉證責任？', '["地方主管機關", "雇主", "求職者或受僱者", "家屬"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:11+00:00", "source_pdf_sha1": "702601c709e6", "answer_pdf_sha1": "1ca8c696a53d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社政法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL)
